import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week');

  // Данные с бэкенда
  const [dashboard, setDashboard] = useState(null);
  const [popularListings, setPopularListings] = useState([]);
  const [searchQueries, setSearchQueries] = useState([]);
  const [priceStats, setPriceStats] = useState(null);

  useEffect(() => {
    loadAllAnalytics();
  }, [period]);

  const loadAllAnalytics = async () => {
    setLoading(true);
    setError(null);

    try {
      // Загружаем все данные параллельно
      const [dashboardData, popularData, queriesData, priceData] = await Promise.all([
        API.get('/analytics/dashboard'),
        API.get(`/analytics/listings/popular?period=${period}`),
        API.get('/analytics/search/queries?days=7'),
        API.get('/analytics/prices/average?city=москва')
      ]);

      setDashboard(dashboardData.data);
      setPopularListings(popularData.data);
      setSearchQueries(queriesData.data.popular_queries || []);
      setPriceStats(priceData.data);
    } catch (err) {
      console.error('Ошибка загрузки аналитики:', err);
      setError('Не удалось загрузить данные аналитики');
    } finally {
      setLoading(false);
    }
  };

// if (!user || user.role_id !== 1) {
//   return (
//     <div className="analytics-error">
//       <h2>Доступ запрещен</h2>
//       <p>Эта страница доступна только администраторам</p>
//     </div>
//   );
// }
  if (loading) return <div className="loader">Загрузка аналитики...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="analytics-page">
      <h1>Аналитика</h1>

      {/* Период */}
      <div className="period-selector">
        <button
          className={period === 'day' ? 'active' : ''}
          onClick={() => setPeriod('day')}
        >
          День
        </button>
        <button
          className={period === 'week' ? 'active' : ''}
          onClick={() => setPeriod('week')}
        >
          Неделя
        </button>
        <button
          className={period === 'month' ? 'active' : ''}
          onClick={() => setPeriod('month')}
        >
          Месяц
        </button>
      </div>

      {/* Карточки с метриками */}
      {dashboard && (
        <div className="metrics-grid">
          <div className="metric-card">
            <h3>Всего объявлений</h3>
            <p className="metric-value">{dashboard.total_listings || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Активных сегодня</h3>
            <p className="metric-value">{dashboard.active_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Просмотров сегодня</h3>
            <p className="metric-value">{dashboard.views_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Новых сегодня</h3>
            <p className="metric-value">{dashboard.new_listings_today || 0}</p>
          </div>
        </div>
      )}

      {/* Две колонки */}
      <div className="analytics-columns">
        {/* Левая колонка - популярные объявления */}
        <div className="analytics-card">
          <h2>Популярные объявления</h2>
          <div className="listings-list">
            {popularListings.map((listing, index) => (
              <div key={listing.listing_id || index} className="listing-item">
                <span className="rank">{index + 1}</span>
                <div className="listing-info">
                  <h4>{listing.title || 'Без названия'}</h4>
                  <p>{listing.address || 'Адрес не указан'}</p>
                </div>
                <span className="views">{listing.views || 0} просмотров</span>
              </div>
            ))}
            {popularListings.length === 0 && (
              <p className="no-data">Нет данных за выбранный период</p>
            )}
          </div>
        </div>

        {/* Правая колонка - поисковые запросы */}
        <div className="analytics-card">
          <h2>Популярные запросы</h2>
          <div className="queries-list">
            {searchQueries.map((item, index) => (
              <div key={index} className="query-item">
                <span className="rank">{index + 1}</span>
                <span className="query">{item.query || 'Пустой запрос'}</span>
                <span className="count">{item.count || 0} раз</span>
              </div>
            ))}
            {searchQueries.length === 0 && (
              <p className="no-data">Нет данных о поиске</p>
            )}
          </div>
        </div>
      </div>

      {/* Статистика цен */}
      {priceStats && (
        <div className="analytics-card">
          <h2>Статистика цен</h2>
          <div className="price-stats">
            <div className="stat-row">
              <span>Средняя цена:</span>
              <strong>{priceStats.avg_price?.toLocaleString() || 0} ₽</strong>
            </div>
            <div className="stat-row">
              <span>Цена за м²:</span>
              <strong>{priceStats.avg_price_per_m2?.toLocaleString() || 0} ₽</strong>
            </div>
            <div className="stat-row">
              <span>Всего предложений:</span>
              <strong>{priceStats.listings_count || 0}</strong>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminAnalytics;
